import React, { useState } from "react";
import { Imgdb, Namedb } from "../components/firebase_setup";
//import { v4 } from "uuid";
import { collection, getDocs } from "firebase/firestore";
import { useNavigate } from "react-router-dom";


function Feed() {
  console.log("This is the feed");
  const navigate = useNavigate();

  const [pdata, setPData] = useState([]);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
  };

  const getData = async() => {
    const dataref = collection(Namedb, "ProfileData");
    const dataDb = await getDocs(dataref);
  }

  return (
    <div className="Feed">
        <h1>This would be the main feed page
            Hopefully you get to see post, comment and like things
        </h1>
        <button className="Logoutbut" onClick={handleLogout}>Logout</button>
    </div>

    
  );
}

export default Feed;
